1	/**
2	 * EvidenceValidator — deterministic verification that a model-proposed
3	 * `exactQuote` physically exists in its claimed source text.
4	 *
5	 * This is the binary provenance check from
6	 * docs/oracle/03-candidate-before-claim-validation.md "Provenance vs.
7	 * Corroboration". If this fails, the candidate must be destroyed.
8	 *
9	 * R2 ships the core logic (.includes + offsets, single-source). The full
10	 * spec (normalization policy, edited-message rejection, multi-line
11	 * boundaries) lands in R5 (claim extraction worker) where the full
12	 * candidate-before-claim pipeline is wired up.
13	 */
14	
15	export type QuoteValidationVerdict =
16	  | 'exact_match'
17	  | 'normalized_match'
18	  | 'failed'
19	  | 'ambiguous';
20	
21	export interface QuoteValidationResult {
22	  verdict: QuoteValidationVerdict;
23	  validatedExactQuote?: string;
24	  validatedCharStart?: number;
25	  validatedCharEnd?: number;
26	  validationMethod: 'verbatim_includes' | 'verbatim_offset_match' | 'none';
27	  detail: string;
28	}
29	
30	export interface ValidateQuoteArgs {
31	  /** The source text the model claims to be quoting from. */
32	  sourceText: string;
33	  /** The quote the model produced. */
34	  exactQuoteProvided: string;
35	  /** Optional char offsets the model provided. */
36	  charStartProvided?: number;
37	  charEndProvided?: number;
38	}
39	
40	export class EvidenceValidator {
41	  validateQuote(args: ValidateQuoteArgs): QuoteValidationResult {
42	    const { sourceText, exactQuoteProvided, charStartProvided, charEndProvided } = args;
43	
44	    if (!exactQuoteProvided || exactQuoteProvided.length === 0) {
45	      return {
46	        verdict: 'failed',
47	        validationMethod: 'none',
48	        detail: 'exactQuoteProvided is empty.',
49	      };
50	    }
51	
52	    // If offsets were given, prefer them. They must match exactly.
53	    if (typeof charStartProvided === 'number' && typeof charEndProvided === 'number') {
54	      const slice = sourceText.slice(charStartProvided, charEndProvided);
55	      if (slice === exactQuoteProvided) {
56	        return {
57	          verdict: 'exact_match',
58	          validatedExactQuote: slice,
59	          validatedCharStart: charStartProvided,
60	          validatedCharEnd: charEndProvided,
61	          validationMethod: 'verbatim_offset_match',
62	          detail: 'Quote matched exactly at provided offsets.',
63	        };
64	      }
65	      return {
66	        verdict: 'failed',
67	        validationMethod: 'verbatim_offset_match',
68	        detail: `Source text at offsets [${charStartProvided}, ${charEndProvided}] does not equal exactQuoteProvided.`,
69	      };
70	    }
71	
72	    // No offsets — scan for the quote.
73	    const firstIdx = sourceText.indexOf(exactQuoteProvided);
74	    if (firstIdx === -1) {
75	      return {
76	        verdict: 'failed',
77	        validationMethod: 'verbatim_includes',
78	        detail: 'exactQuoteProvided was not found in sourceText.',
79	      };
80	    }
81	    // Ambiguity check: if the quote appears more than once we cannot be sure
82	    // which occurrence is the source. Reject unless the model provides offsets.
83	    const secondIdx = sourceText.indexOf(exactQuoteProvided, firstIdx + 1);
84	    if (secondIdx !== -1) {
85	      return {
86	        verdict: 'ambiguous',
87	        validationMethod: 'verbatim_includes',
88	        detail: 'Quote appears more than once in sourceText. Model must provide explicit offsets.',
89	      };
90	    }
91	    return {
92	      verdict: 'exact_match',
93	      validatedExactQuote: exactQuoteProvided,
94	      validatedCharStart: firstIdx,
95	      validatedCharEnd: firstIdx + exactQuoteProvided.length,
96	      validationMethod: 'verbatim_includes',
97	      detail: 'Quote matched exactly via single-occurrence includes() scan.',
98	    };
99	  }
100	}
101	
102	let cached: EvidenceValidator | null = null;
103	export function getEvidenceValidator(): EvidenceValidator {
104	  if (!cached) cached = new EvidenceValidator();
105	  return cached;
106	}
