1	/**
2	 * R5 normalization helpers.
3	 *
4	 * Every helper is pure. They produce a normalized form of the input string
5	 * given the supplied policy, and they signal (via the return shape) exactly
6	 * which normalizations actually changed the input so the quote validator
7	 * can report the precise method that succeeded.
8	 *
9	 * Default policy is no normalization. Enable options selectively, never
10	 * blanket-on, because each normalization erodes provenance.
11	 */
12	
13	import type { NormalizationPolicy, ValidationMethod } from './types';
14	
15	export interface NormalizedString {
16	  text: string;
17	  /** Which normalizations the policy enabled that actually changed the text. */
18	  applied: NonNullable<keyof NormalizationPolicy>[];
19	}
20	
21	/** Replace CRLF and bare CR with LF. */
22	function normalizeCRLF(s: string): string {
23	  return s.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
24	}
25	
26	/**
27	 * Map common smart-quote variants to their straight equivalents.
28	 *   ‘ ’ ‚ ‛  → '
29	 *   “ ” „ ‟  → "
30	 *   ‹ ›        → '
31	 *   « »        → "
32	 *   …          → '...'
33	 *   – —        → '-'
34	 */
35	function normalizeSmartQuotes(s: string): string {
36	  return s
37	    .replace(/[‘’‚‛‹›]/g, "'")
38	    .replace(/[“”„‟«»]/g, '"')
39	    .replace(/…/g, '...')
40	    .replace(/[–—]/g, '-');
41	}
42	
43	/** Collapse runs of internal whitespace to a single space. */
44	function normalizeInternalWhitespace(s: string): string {
45	  return s.replace(/[ \t\f\v]+/g, ' ').replace(/[ \t\f\v]*\n[ \t\f\v]*/g, '\n');
46	}
47	
48	/** Strip leading/trailing whitespace. */
49	function normalizeTrim(s: string): string {
50	  return s.trim();
51	}
52	
53	/**
54	 * Apply the policy. Returns the normalized text and the list of options
55	 * that actually changed the input (so callers can report the precise
56	 * method that succeeded).
57	 */
58	export function normalize(input: string, policy: NormalizationPolicy): NormalizedString {
59	  const applied: NonNullable<keyof NormalizationPolicy>[] = [];
60	  let out = input;
61	
62	  if (policy.allowCRLF) {
63	    const next = normalizeCRLF(out);
64	    if (next !== out) applied.push('allowCRLF');
65	    out = next;
66	  }
67	  if (policy.allowSmartQuotes) {
68	    const next = normalizeSmartQuotes(out);
69	    if (next !== out) applied.push('allowSmartQuotes');
70	    out = next;
71	  }
72	  if (policy.allowWhitespaceCollapse) {
73	    const next = normalizeInternalWhitespace(out);
74	    if (next !== out) applied.push('allowWhitespaceCollapse');
75	    out = next;
76	  }
77	  if (policy.allowLeadingTrailingTrim) {
78	    const next = normalizeTrim(out);
79	    if (next !== out) applied.push('allowLeadingTrailingTrim');
80	    out = next;
81	  }
82	
83	  return { text: out, applied };
84	}
85	
86	/** Pick the most precise ValidationMethod tag given the applied normalizations. */
87	export function methodForApplied(applied: NonNullable<keyof NormalizationPolicy>[]): ValidationMethod {
88	  if (applied.length === 0) return 'verbatim_includes';
89	  if (applied.length > 1) return 'normalized_combined';
90	  switch (applied[0]) {
91	    case 'allowCRLF':
92	      return 'normalized_crlf';
93	    case 'allowSmartQuotes':
94	      return 'normalized_smart_quotes';
95	    case 'allowWhitespaceCollapse':
96	      return 'normalized_whitespace';
97	    case 'allowLeadingTrailingTrim':
98	      return 'normalized_trim';
99	    default:
100	      // Unreachable in practice — every NormalizationPolicy key is handled
101	      // above. The default exists so the compiler can prove exhaustiveness
102	      // even after new policy keys are added without their case arms.
103	      return 'normalized_combined';
104	  }
105	}
