1	/**
2	 * R5 — Candidate promotion service.
3	 *
4	 * Concurrency-locked, idempotent promotion from staging
5	 * (`extraction_candidates` + `extraction_candidate_evidence`) to permanent
6	 * tables (`claims` + `claim_top_domains` + `claim_evidence`).
7	 *
8	 * Per docs/oracle/03-candidate-before-claim-validation.md
9	 * "Candidate promotion transaction (Concurrency Locked)":
10	 *
11	 *   1. Begin transaction.
12	 *   2. Acquire advisory lock on hashtextextended(candidateHash, 0).
13	 *   3. Confirm candidate status is 'validated' and not already promoted.
14	 *   4. Check for an existing claim with the same hash. If found, append
15	 *      THIS candidate's evidence to that claim instead of inserting a
16	 *      duplicate, and mark this candidate as 'duplicate'.
17	 *   5. Otherwise insert claims + claim_top_domains + claim_evidence atomically.
18	 *   6. Update candidate to 'promoted' (or 'duplicate') with timestamps.
19	 *   7. Commit.
20	 *
21	 * The transactional executor is wired to Drizzle in
22	 * `runPromotionInTransaction` below. The DECISION logic — what to insert,
23	 * what to append, what to reject — is extracted into `decidePromotion` as
24	 * a pure function so the 6 R5 tests can exercise it without a real DB.
25	 */
26	
27	import type { EntityType, EvidenceSourceType } from '@oracle/shared';
28	import type {
29	  EntityProposalToCreate,
30	  ResolvedEntityAssignment,
31	} from './taxonomy-validator';
32	
33	// ─────────────────────────────────────────────────────────────────────────
34	// Decision shapes — what the promoter sees, what it decides to do.
35	// ─────────────────────────────────────────────────────────────────────────
36	
37	/** Claim-level metadata the model surfaced (per R5.5). Goes into claim_metadata. */
38	export interface CandidateMetadata {
39	  processStage?: string | null;
40	  department?: string | null;
41	  geography?: string | null;
42	  documentClass?: string | null;
43	  effectiveFrom?: Date | null;
44	  effectiveUntil?: Date | null;
45	}
46	
47	export interface CandidateSnapshot {
48	  /** Hashed canonical representation of the candidate (see candidate-hash.ts). */
49	  candidateHash: string;
50	
51	  /** From `extraction_candidates`. */
52	  candidate: {
53	    id: string;
54	    status: string;
55	    summary: string;
56	    claimType: string;
57	    impactScore: number;
58	    confidenceScore?: number;
59	    domains: string[];
60	    promotedToClaimId?: string | null;
61	  };
62	
63	  /** From `extraction_candidate_evidence`. Only rows with validationStatus in (exact_match, normalized_match). */
64	  validatedEvidence: Array<{
65	    id: string;
66	    sourceType: EvidenceSourceType;
67	    sourceMessageId?: string | null;
68	    sourceDocumentChunkId?: string | null;
69	    sourceExternalRecordId?: string | null;
70	    assertedByEmployeeId?: string | null;
71	    uploadedByEmployeeId?: string | null;
72	    createdByEmployeeId?: string | null;
73	    validatedExactQuote: string;
74	    validatedCharStart: number;
75	    validatedCharEnd: number;
76	    pageNumber?: number | null;
77	    confidence?: number | null;
78	    /** R5.5 — surfaced per evidence row when the model could infer them. */
79	    documentClass?: string | null;
80	    processStage?: string | null;
81	  }>;
82	
83	  /**
84	   * R5.5 — Taxonomy validation result (from `validateTaxonomy`). Optional
85	   * for backward compatibility with R5 callers that don't run the
86	   * taxonomy validator yet.
87	   *
88	   * When present:
89	   *  - `validTopDomainIds` replaces `candidate.domains` as the set of
90	   *    top-domain rows we'll actually write.
91	   *  - `resolvedEntities` becomes the claim_entities inserts.
92	   *  - `entityProposalsToCreate` are staged BEFORE the promotion runs.
93	   *  - `taxonomyOk: false` blocks promotion entirely.
94	   */
95	  taxonomy?: {
96	    ok: boolean;
97	    validTopDomainIds: string[];
98	    resolvedEntities: ResolvedEntityAssignment[];
99	    entityProposalsToCreate: EntityProposalToCreate[];
100	    failureSummary?: string;
101	  };
102	
103	  /** R5.5 — Claim-level metadata to write to claim_metadata. */
104	  metadata?: CandidateMetadata;
105	
106	  /**
107	   * The claim — if any — that the candidate's hash matches. The promoter
108	   * checks this INSIDE the transaction so a worker racing for the lock
109	   * sees the latest committed state.
110	   */
111	  existingClaimWithSameHash?: { claimId: string } | null;
112	}
113	
114	/** R5.5 — Entity tag assignments to write to claim_entities. */
115	export interface EntityAssignment {
116	  entityId: string;
117	  entityType: EntityType;
118	  canonicalValue: string;
119	}
120	
121	export type PromotionDecision =
122	  | {
123	      kind: 'insert_new_claim';
124	      /** Stable hash this claim will be associated with via the candidate. */
125	      candidateHash: string;
126	      claim: {
127	        claimType: string;
128	        summary: string;
129	        impactScore: number;
130	        confidenceScore?: number;
131	        // R3.5+: status is now a varchar (per oracle_master_spec §6.6),
132	        // but the existing claims table still uses claimStatusEnum until
133	        // R6 migrates the schema. Promotion inserts 'pending_review' — the
134	        // admin queue does the final approval.
135	        status: 'pending_review';
136	      };
137	      topDomainAssignments: Array<{ topDomainId: string; assignmentReason: 'extraction' }>;
138	      /** R5.5 — claim_entities rows to insert. Empty when the candidate had no entities. */
139	      entityAssignments: EntityAssignment[];
140	      /** R5.5 — claim_metadata row to insert. Undefined when no metadata was surfaced. */
141	      metadata?: CandidateMetadata;
142	      /** R5.5 — entity_proposals rows to stage before the promotion runs. */
143	      entityProposalsToStage: EntityProposalToCreate[];
144	      evidenceRows: CandidateSnapshot['validatedEvidence'];
145	      candidateUpdate: { status: 'promoted'; setPromotedToClaimId: true };
146	    }
147	  | {
148	      kind: 'append_to_existing_claim';
149	      candidateHash: string;
150	      existingClaimId: string;
151	      /** R5.5 — entity tags to merge onto the existing claim. */
152	      entityAssignments: EntityAssignment[];
153	      /** R5.5 — entity_proposals to stage even when the candidate is a duplicate. */
154	      entityProposalsToStage: EntityProposalToCreate[];
155	      evidenceRows: CandidateSnapshot['validatedEvidence'];
156	      candidateUpdate: { status: 'duplicate'; setDuplicateOfClaimId: string };
157	    }
158	  | {
159	      kind: 'reject';
160	      reason:
161	        | 'not_validated'
162	        | 'already_promoted'
163	        | 'no_validated_evidence'
164	        | 'no_domains'
165	        | 'taxonomy_invalid'
166	        | 'invalid_state';
167	      detail: string;
168	      /** R5.5 — even rejected candidates may surface entity proposals worth staging. */
169	      entityProposalsToStage?: EntityProposalToCreate[];
170	    };
171	
172	// ─────────────────────────────────────────────────────────────────────────
173	// Pure decision function — testable without a DB.
174	// ─────────────────────────────────────────────────────────────────────────
175	
176	export function decidePromotion(snapshot: CandidateSnapshot): PromotionDecision {
177	  const { candidate, validatedEvidence, candidateHash, existingClaimWithSameHash, taxonomy, metadata } =
178	    snapshot;
179	
180	  // Entity proposals are worth surfacing even when we reject — admin can
181	  // review the proposals separately. We thread them through every branch.
182	  const entityProposalsToStage = taxonomy?.entityProposalsToCreate ?? [];
183	
184	  // Idempotency: re-running the promoter on an already-promoted candidate
185	  // returns 'already_promoted' without trying to insert anything.
186	  if (candidate.status === 'promoted') {
187	    return {
188	      kind: 'reject',
189	      reason: 'already_promoted',
190	      detail: `Candidate ${candidate.id} is already promoted to claim ${candidate.promotedToClaimId ?? '<unknown>'}.`,
191	      entityProposalsToStage,
192	    };
193	  }
194	
195	  // The candidate must be 'validated' before promotion. Anything else
196	  // (pending_validation, validation_failed, rejected, *_sensitive) gets
197	  // rejected here — the only way out of those states is review, not promotion.
198	  if (candidate.status !== 'validated') {
199	    return {
200	      kind: 'reject',
201	      reason: 'not_validated',
202	      detail: `Candidate ${candidate.id} has status "${candidate.status}", must be "validated" to promote.`,
203	      entityProposalsToStage,
204	    };
205	  }
206	
207	  if (validatedEvidence.length === 0) {
208	    return {
209	      kind: 'reject',
210	      reason: 'no_validated_evidence',
211	      detail: `Candidate ${candidate.id} has no evidence rows with validation_status in (exact_match, normalized_match).`,
212	      entityProposalsToStage,
213	    };
214	  }
215	
216	  // R5.5: taxonomy validation blocks promotion. Even if the only failure
217	  // is "unknown entity needs proposal", we hold the candidate so admin
218	  // can resolve the entity registry before a claim is written with a
219	  // half-correct tag set.
220	  if (taxonomy && !taxonomy.ok) {
221	    return {
222	      kind: 'reject',
223	      reason: 'taxonomy_invalid',
224	      detail:
225	        `Candidate ${candidate.id} failed taxonomy validation. ` +
226	        (taxonomy.failureSummary ?? 'See extraction_validation_results for the per-check breakdown.'),
227	      entityProposalsToStage,
228	    };
229	  }
230	
231	  // The effective top-domain ID list is the taxonomy-validated subset when
232	  // available, otherwise the raw candidate.domains (R5 callers).
233	  const effectiveTopDomainIds = taxonomy ? taxonomy.validTopDomainIds : candidate.domains;
234	  if (!effectiveTopDomainIds || effectiveTopDomainIds.length === 0) {
235	    return {
236	      kind: 'reject',
237	      reason: 'no_domains',
238	      detail: `Candidate ${candidate.id} has no valid top-domain IDs after taxonomy validation.`,
239	      entityProposalsToStage,
240	    };
241	  }
242	
243	  const entityAssignments: EntityAssignment[] = (taxonomy?.resolvedEntities ?? []).map((e) => ({
244	    entityId: e.entityId,
245	    entityType: e.entityType,
246	    canonicalValue: e.canonicalValue,
247	  }));
248	
249	  // Duplicate detection. The advisory lock means we're the only writer
250	  // holding this hash; if there's still an existing claim row, another
251	  // worker won the race already and we append our evidence to theirs.
252	  if (existingClaimWithSameHash) {
253	    return {
254	      kind: 'append_to_existing_claim',
255	      candidateHash,
256	      existingClaimId: existingClaimWithSameHash.claimId,
257	      entityAssignments,
258	      entityProposalsToStage,
259	      evidenceRows: validatedEvidence,
260	      candidateUpdate: {
261	        status: 'duplicate',
262	        setDuplicateOfClaimId: existingClaimWithSameHash.claimId,
263	      },
264	    };
265	  }
266	
267	  // Happy path: insert a new claim, the top-domain rows, the entity
268	  // tag rows, the metadata row, and the evidence rows, atomically.
269	  return {
270	    kind: 'insert_new_claim',
271	    candidateHash,
272	    claim: {
273	      claimType: candidate.claimType,
274	      summary: candidate.summary,
275	      impactScore: candidate.impactScore,
276	      confidenceScore: candidate.confidenceScore,
277	      status: 'pending_review',
278	    },
279	    topDomainAssignments: effectiveTopDomainIds.map((id) => ({
280	      topDomainId: id,
281	      assignmentReason: 'extraction',
282	    })),
283	    entityAssignments,
284	    metadata: metadata && hasAnyMetadata(metadata) ? metadata : undefined,
285	    entityProposalsToStage,
286	    evidenceRows: validatedEvidence,
287	    candidateUpdate: { status: 'promoted', setPromotedToClaimId: true },
288	  };
289	}
290	
291	/** Internal — true if at least one field in the metadata payload is non-null. */
292	function hasAnyMetadata(m: CandidateMetadata): boolean {
293	  return Boolean(
294	    m.processStage ||
295	      m.department ||
296	      m.geography ||
297	      m.documentClass ||
298	      m.effectiveFrom ||
299	      m.effectiveUntil,
300	  );
301	}
302	
303	// ─────────────────────────────────────────────────────────────────────────
304	// Executor stub.
305	//
306	// The full Drizzle wiring lands when R6 actually calls into this from the
307	// claim-extraction worker. The stub below documents the exact SQL surface
308	// the executor will use so reviewers can audit the transactional shape
309	// without grepping for it later.
310	// ─────────────────────────────────────────────────────────────────────────
311	
312	/**
313	 * Pseudo-code the executor MUST follow when R6 wires this up to Drizzle.
314	 * The pure `decidePromotion` is the spec; this is the runbook for turning
315	 * that decision into SQL.
316	 *
317	 * ```ts
318	 * await db.transaction(async (tx) => {
319	 *   // 1. Advisory lock keyed on the candidate hash.
320	 *   //    pg_try_advisory_xact_lock returns FALSE if another tx holds it —
321	 *   //    the worker should back off and retry rather than block forever.
322	 *   const lockRes = await tx.execute(
323	 *     sql`SELECT pg_try_advisory_xact_lock(hashtextextended(${candidateHash}, 0)) AS locked`
324	 *   );
325	 *   if (!lockRes[0].locked) throw new AdvisoryLockBusyError(candidateHash);
326	 *
327	 *   // 2. Re-read the candidate state INSIDE the lock so we see the latest
328	 *   //    committed view of the world.
329	 *   const candidate = await tx.query.extractionCandidates.findFirst({
330	 *     where: eq(extractionCandidates.id, candidateId),
331	 *     with: { evidence: true },
332	 *   });
333	 *
334	 *   // 3. Look for an existing claim with the same hash. We could store the
335	 *   //    candidate hash on claims directly, or compute it on the fly from a
336	 *   //    join across claim_top_domains and claim_evidence. R6 will pick the
337	 *   //    cheaper option after evals; for now we recommend a hash column on
338	 *   //    claims with a UNIQUE index for O(1) lookup.
339	 *
340	 *   // 4. Run the pure decider.
341	 *   const decision = decidePromotion(snapshot);
342	 *
343	 *   // 5. Apply the decision.
344	 *   switch (decision.kind) {
345	 *     case 'insert_new_claim': {
346	 *       const claimRow = await tx.insert(claims).values(decision.claim).returning();
347	 *       await tx.insert(claimTopDomains).values(
348	 *         decision.topDomainAssignments.map((a) => ({ claimId: claimRow.id, ...a }))
349	 *       );
350	 *       await tx.insert(claimEvidence).values(
351	 *         decision.evidenceRows.map((e) => ({ claimId: claimRow.id, ...e }))
352	 *       );
353	 *       await tx.update(extractionCandidates).set({
354	 *         status: 'promoted',
355	 *         promotedToClaimId: claimRow.id,
356	 *         promotedAt: new Date(),
357	 *       }).where(eq(extractionCandidates.id, candidateId));
358	 *       break;
359	 *     }
360	 *     case 'append_to_existing_claim': {
361	 *       await tx.insert(claimEvidence).values(
362	 *         decision.evidenceRows.map((e) => ({ claimId: decision.existingClaimId, ...e }))
363	 *       );
364	 *       await tx.update(extractionCandidates).set({
365	 *         status: 'duplicate',
366	 *         duplicateOfClaimId: decision.existingClaimId,
367	 *         promotedAt: new Date(),
368	 *       }).where(eq(extractionCandidates.id, candidateId));
369	 *       break;
370	 *     }
371	 *     case 'reject': {
372	 *       await tx.insert(extractionValidationResults).values({
373	 *         candidateId,
374	 *         checkName: 'promotion_transaction',
375	 *         status: 'fail',
376	 *         detail: `${decision.reason}: ${decision.detail}`,
377	 *       });
378	 *       break;
379	 *     }
380	 *   }
381	 * });
382	 * ```
383	 *
384	 * R6 lifts that runbook into a real function. R5 ships the decider and
385	 * the candidate hash so the runbook is just SQL plumbing.
386	 */
387	export const PROMOTION_TRANSACTION_RUNBOOK = 'See JSDoc in promote-candidate.ts';
388

1	/**
2	 * R11.1 — Proactive interjection decision logic (pure).
3	 *
4	 * Two decisions per spec Part 5.1:
5	 *
6	 *   1. decideLullInterjection — when the conversation has gone quiet, should
7	 *      the Oracle pop a high-priority open gap as a question?
8	 *
9	 *   2. decideContradictionInterjection — when the contradiction-watcher finds
10	 *      a real semantic clash between two approved claims, should the Oracle
11	 *      surface it LIVE in chat, or file it silently for synthesis to digest?
12	 *
13	 * Both are pure functions: in → out, no DB, no I/O. The Trigger.dev tasks
14	 * (R11.2 lull-interjection, R11.3 contradiction-watcher live branch) pass
15	 * pre-fetched data in; the functions just decide. Smoke gate at
16	 * `packages/oracle-engines/src/__verify__/r11-1-interjection-decision-smoke.ts`
17	 * exercises every gate path without spinning up a database.
18	 *
19	 * Decision rationale (all calls) is returned as a `reason` string so admin
20	 * dashboards and `oracle_interventions` audit rows can show exactly why a
21	 * given interjection did or didn't happen.
22	 *
23	 * Per spec Part 5.1 and `docs/oracle/05-ai-retrofit-phase-packet.md` "Phase R11".
24	 */
25	
26	// ─── Lull interjection ─────────────────────────────────────────────────────
27	
28	export type ChannelKind = 'dm' | 'group';
29	
30	export interface RelevantOpenGap {
31	  /** `gaps.id` */
32	  id: string;
33	  /** `gaps.priority` — `low | medium | high | urgent` per the priority enum. */
34	  priority: 'low' | 'medium' | 'high' | 'urgent';
35	  /** `gaps.question_to_ask` — what we'd actually ask the room. */
36	  questionToAsk: string;
37	  /** `gaps.why_it_matters` — context for the asker that draft prompts can lean on. */
38	  whyItMatters: string;
39	}
40	
41	export interface LullInterjectionInput {
42	  /** Time since the last NON-Oracle (`role='user'`) message in the channel. */
43	  secondsSinceLastUserMessage: number;
44	  /** `settings.lull_window_seconds` — minimum silence before considering an interjection. */
45	  lullWindowSeconds: number;
46	  /** Realtime presence — is anyone currently typing? Skip if so. */
47	  isAnyoneTyping: boolean;
48	  /** Time since the most recent oracle_intervention in this channel, or null if none ever. */
49	  minutesSinceLastOracleInterjection: number | null;
50	  /** `settings.oracle_cooldown_minutes` — minimum gap between interjections in one channel. */
51	  oracleCooldownMinutes: number;
52	  /** Count of oracle_interventions in this channel in the last 60 minutes. */
53	  interjectionsInLastHour: number;
54	  /** `settings.max_oracle_interjections_per_hour` — hard cap per channel per hour. */
55	  maxOracleInterjectionsPerHour: number;
56	  /** `settings.enable_group_chat_lull_questions` — global kill switch for group chats. */
57	  enableGroupChatLullQuestions: boolean;
58	  /** DMs always allow lull questions; group chats require the setting above. */
59	  channelKind: ChannelKind;
60	  /**
61	   * Highest-priority open gap topically relevant to the recent conversation.
62	   * Null = no relevant gap available, skip.
63	   */
64	  topRelevantOpenGap: RelevantOpenGap | null;
65	}
66	
67	export type LullInterjectionDecision =
68	  | {
69	      decision: 'ask';
70	      gapId: string;
71	      reason: string;
72	    }
73	  | {
74	      decision: 'skip';
75	      reason: string;
76	      /** Stable code for dashboard grouping. */
77	      reasonCode:
78	        | 'group_lull_disabled'
79	        | 'lull_window_not_elapsed'
80	        | 'someone_typing'
81	        | 'cooldown_active'
82	        | 'rate_cap_reached'
83	        | 'no_relevant_gap';
84	    };
85	
86	/**
87	 * Decide whether the Oracle should ask a lull question right now.
88	 *
89	 * Gates evaluate in this order — first failed gate wins, no further checks:
90	 *   1. Group-chat lull disabled (setting off + channel is group) → skip
91	 *   2. Not enough silence yet → skip
92	 *   3. Someone is typing → skip
93	 *   4. Cooldown not elapsed → skip
94	 *   5. Per-channel hourly rate cap reached → skip
95	 *   6. No relevant open gap to ask about → skip
96	 *   7. All gates pass → ask
97	 */
98	export function decideLullInterjection(
99	  input: LullInterjectionInput,
100	): LullInterjectionDecision {
101	  // 1. Group-chat kill switch
102	  if (input.channelKind === 'group' && !input.enableGroupChatLullQuestions) {
103	    return {
104	      decision: 'skip',
105	      reason: 'enable_group_chat_lull_questions=false; Oracle stays quiet in group chats.',
106	      reasonCode: 'group_lull_disabled',
107	    };
108	  }
109	
110	  // 2. Lull window
111	  if (input.secondsSinceLastUserMessage < input.lullWindowSeconds) {
112	    return {
113	      decision: 'skip',
114	      reason: `Conversation has been quiet for only ${input.secondsSinceLastUserMessage}s; lull window is ${input.lullWindowSeconds}s.`,
115	      reasonCode: 'lull_window_not_elapsed',
116	    };
117	  }
118	
119	  // 3. Presence — don't interrupt typing
120	  if (input.isAnyoneTyping) {
121	    return {
122	      decision: 'skip',
123	      reason: 'Someone is currently typing; Oracle does not interrupt.',
124	      reasonCode: 'someone_typing',
125	    };
126	  }
127	
128	  // 4. Cooldown — minutesSinceLastOracleInterjection=null means "never" => not in cooldown
129	  if (
130	    input.minutesSinceLastOracleInterjection != null &&
131	    input.minutesSinceLastOracleInterjection < input.oracleCooldownMinutes
132	  ) {
133	    return {
134	      decision: 'skip',
135	      reason: `Last Oracle interjection was ${input.minutesSinceLastOracleInterjection}min ago; cooldown is ${input.oracleCooldownMinutes}min.`,
136	      reasonCode: 'cooldown_active',
137	    };
138	  }
139	
140	  // 5. Per-hour rate cap
141	  if (input.interjectionsInLastHour >= input.maxOracleInterjectionsPerHour) {
142	    return {
143	      decision: 'skip',
144	      reason: `Channel has already received ${input.interjectionsInLastHour} Oracle interjection(s) this hour; cap is ${input.maxOracleInterjectionsPerHour}.`,
145	      reasonCode: 'rate_cap_reached',
146	    };
147	  }
148	
149	  // 6. Relevant open gap available?
150	  if (!input.topRelevantOpenGap) {
151	    return {
152	      decision: 'skip',
153	      reason: 'No open gap topically relevant to recent conversation; nothing to ask.',
154	      reasonCode: 'no_relevant_gap',
155	    };
156	  }
157	
158	  // 7. All gates pass
159	  return {
160	    decision: 'ask',
161	    gapId: input.topRelevantOpenGap.id,
162	    reason: `Lull window elapsed (${input.secondsSinceLastUserMessage}s ≥ ${input.lullWindowSeconds}s), cooldown clear, ${input.interjectionsInLastHour}/${input.maxOracleInterjectionsPerHour} interjections this hour, asking ${input.topRelevantOpenGap.priority}-priority gap ${input.topRelevantOpenGap.id}.`,
163	  };
164	}
165	
166	// ─── Contradiction interjection ─────────────────────────────────────────────
167	
168	export type ContradictionSeverity = 'low' | 'medium' | 'high';
169	
170	/**
171	 * Confidence threshold for live interjection. Below this, even a `high`-
172	 * severity contradiction stays queued. The contradiction-watcher's
173	 * adjudication LLM reports a 0-100 confidence; 80 is the spec default per
174	 * the legacy worker. Adjustable per future eval.
175	 */
176	export const CONTRADICTION_LIVE_CONFIDENCE_THRESHOLD = 80 as const;
177	
178	export interface ContradictionInterjectionInput {
179	  /** 0-100. LLM-reported `detectionConfidence` from the adjudication call. */
180	  detectionConfidence: number;
181	  /** `contradictions.severity`. */
182	  severity: ContradictionSeverity;
183	  /** `settings.enable_live_contradiction_interjections` — global kill switch. */
184	  enableLiveContradictionInterjections: boolean;
185	  /** Time since the most recent oracle_intervention in the channel this contradiction relates to. */
186	  minutesSinceLastOracleInterjection: number | null;
187	  /** `settings.oracle_cooldown_minutes`. */
188	  oracleCooldownMinutes: number;
189	  /** Count of oracle_interventions in the channel in the last 60 minutes. */
190	  interjectionsInLastHour: number;
191	  /** `settings.max_oracle_interjections_per_hour`. */
192	  maxOracleInterjectionsPerHour: number;
193	  /** Model-suggested question that would surface the contradiction in chat. Null = nothing to post live. */
194	  suggestedQuestion: string | null;
195	}
196	
197	export type ContradictionInterjectionDecision =
198	  | {
199	      decision: 'live';
200	      reason: string;
201	    }
202	  | {
203	      decision: 'queue';
204	      reason: string;
205	      /** Stable code for dashboard grouping. */
206	      reasonCode:
207	        | 'live_setting_off'
208	        | 'severity_too_low'
209	        | 'confidence_too_low'
210	        | 'cooldown_active'
211	        | 'rate_cap_reached'
212	        | 'no_suggested_question';
213	    };
214	
215	/**
216	 * Decide whether a freshly-detected contradiction should be surfaced LIVE in
217	 * chat or filed silently for later synthesis.
218	 *
219	 * Per spec Part 5.1 "Rule 1": most contradictions should NOT cause live
220	 * interjections. Live is reserved for high-severity + high-confidence cases
221	 * where the operational impact is real and admin tolerance is high.
222	 *
223	 * Gates evaluate in this order — first failed gate wins:
224	 *   1. Live-interjection setting off → queue
225	 *   2. Severity below 'high' → queue
226	 *   3. Confidence below threshold → queue
227	 *   4. Cooldown not elapsed in the channel → queue
228	 *   5. Per-channel hourly rate cap reached → queue
229	 *   6. No model-suggested question to post → queue
230	 *   7. All gates pass → live
231	 */
232	export function decideContradictionInterjection(
233	  input: ContradictionInterjectionInput,
234	): ContradictionInterjectionDecision {
235	  // 1. Setting kill switch
236	  if (!input.enableLiveContradictionInterjections) {
237	    return {
238	      decision: 'queue',
239	      reason: 'enable_live_contradiction_interjections=false; filing silently for synthesis.',
240	      reasonCode: 'live_setting_off',
241	    };
242	  }
243	
244	  // 2. Severity threshold (only 'high' is eligible per spec 5.1)
245	  if (input.severity !== 'high') {
246	    return {
247	      decision: 'queue',
248	      reason: `Severity=${input.severity}; live interjection requires severity=high.`,
249	      reasonCode: 'severity_too_low',
250	    };
251	  }
252	
253	  // 3. Confidence threshold
254	  if (input.detectionConfidence < CONTRADICTION_LIVE_CONFIDENCE_THRESHOLD) {
255	    return {
256	      decision: 'queue',
257	      reason: `detectionConfidence=${input.detectionConfidence} below threshold ${CONTRADICTION_LIVE_CONFIDENCE_THRESHOLD}.`,
258	      reasonCode: 'confidence_too_low',
259	    };
260	  }
261	
262	  // 4. Cooldown
263	  if (
264	    input.minutesSinceLastOracleInterjection != null &&
265	    input.minutesSinceLastOracleInterjection < input.oracleCooldownMinutes
266	  ) {
267	    return {
268	      decision: 'queue',
269	      reason: `Last Oracle interjection was ${input.minutesSinceLastOracleInterjection}min ago; cooldown is ${input.oracleCooldownMinutes}min.`,
270	      reasonCode: 'cooldown_active',
271	    };
272	  }
273	
274	  // 5. Per-hour rate cap
275	  if (input.interjectionsInLastHour >= input.maxOracleInterjectionsPerHour) {
276	    return {
277	      decision: 'queue',
278	      reason: `Channel has already received ${input.interjectionsInLastHour} Oracle interjection(s) this hour; cap is ${input.maxOracleInterjectionsPerHour}.`,
279	      reasonCode: 'rate_cap_reached',
280	    };
281	  }
282	
283	  // 6. Need a draftable question
284	  if (!input.suggestedQuestion || input.suggestedQuestion.trim() === '') {
285	    return {
286	      decision: 'queue',
287	      reason: 'Adjudicator did not return a suggested question; cannot draft live message.',
288	      reasonCode: 'no_suggested_question',
289	    };
290	  }
291	
292	  // 7. All gates pass
293	  return {
294	    decision: 'live',
295	    reason: `severity=high, confidence=${input.detectionConfidence}≥${CONTRADICTION_LIVE_CONFIDENCE_THRESHOLD}, cooldown clear, ${input.interjectionsInLastHour}/${input.maxOracleInterjectionsPerHour} this hour — posting live.`,
296	  };
297	}
