1	/**
2	 * R6 — Validation-loop circuit breaker.
3	 *
4	 * Pure decision function. Workers feed in the batch's running counters
5	 * after each attempt and get back a decision: continue, allow one
6	 * structured-repair pass, or trip the breaker.
7	 *
8	 * Spec: docs/oracle/03-candidate-before-claim-validation.md
9	 * "Circuit breakers and infinite-loop prevention". A batch whose
10	 * deterministic quote validation fails 3 times in a row gets:
11	 *   - status: failed_validation_loop
12	 *   - extraction_validation_results row with
13	 *       check_name='validation_loop_circuit_breaker',
14	 *       status='circuit_breaker'
15	 *   - the worker moves on to the next batch.
16	 *
17	 * Allowed exception: ONE structured-repair attempt before the breaker
18	 * trips, if the failure is plausibly schema-shape rather than quote
19	 * hallucination.
20	 */
21	
22	import type { ValidationCheckName, ValidationCheckStatus } from '@oracle/shared';
23	
24	export const DEFAULT_QUOTE_FAILURE_LIMIT = 3;
25	
26	export interface CircuitBreakerInput {
27	  /** Total deterministic-validation attempts made so far on this batch. */
28	  validationAttemptCount: number;
29	  /** Consecutive QUOTE validation failures specifically. */
30	  consecutiveQuoteFailureCount: number;
31	  /**
32	   * True if the most recent failure looked like a schema-shape issue (e.g.
33	   * Zod validation failed) rather than a quote hallucination. Workers pass
34	   * this so we can allow the one-shot repair branch.
35	   */
36	  lastFailureLooksLikeSchema?: boolean;
37	  /**
38	   * Configurable threshold. Defaults to 3. Override only in tests or with
39	   * a deliberate spec change.
40	   */
41	  failureLimit?: number;
42	}
43	
44	export type CircuitBreakerDecision =
45	  | { kind: 'continue'; detail: string }
46	  | { kind: 'allow_repair_pass'; detail: string }
47	  | {
48	      kind: 'trip_breaker';
49	      detail: string;
50	      validationResultToWrite: {
51	        checkName: ValidationCheckName;
52	        status: ValidationCheckStatus;
53	        detail: string;
54	      };
55	    };
56	
57	/**
58	 * Decide what to do based on the batch counters.
59	 *
60	 *  - Under the limit ⇒ continue.
61	 *  - At limit-1 with a schema-shape failure ⇒ allow_repair_pass (one shot).
62	 *  - At limit ⇒ trip the breaker.
63	 */
64	export function decideCircuitBreaker(input: CircuitBreakerInput): CircuitBreakerDecision {
65	  const limit = input.failureLimit ?? DEFAULT_QUOTE_FAILURE_LIMIT;
66	
67	  if (input.consecutiveQuoteFailureCount >= limit) {
68	    return {
69	      kind: 'trip_breaker',
70	      detail:
71	        `Batch has hit ${input.consecutiveQuoteFailureCount} consecutive quote-validation failures` +
72	        ` (limit=${limit}). Mark the batch failed_validation_loop and move on.`,
73	      validationResultToWrite: {
74	        checkName: 'validation_loop_circuit_breaker',
75	        status: 'circuit_breaker',
76	        detail: `Tripped after ${input.consecutiveQuoteFailureCount} consecutive failures.`,
77	      },
78	    };
79	  }
80	
81	  if (
82	    input.consecutiveQuoteFailureCount === limit - 1 &&
83	    input.lastFailureLooksLikeSchema === true
84	  ) {
85	    return {
86	      kind: 'allow_repair_pass',
87	      detail:
88	        'One repair attempt allowed because the last failure looked like a schema-shape issue.' +
89	        ' If it fails too, the next call will trip the breaker.',
90	    };
91	  }
92	
93	  return {
94	    kind: 'continue',
95	    detail: `Under threshold (${input.consecutiveQuoteFailureCount} / ${limit}).`,
96	  };
97	}
