1	/**
2	 * R7 — provider_cached_content lifecycle helpers.
3	 *
4	 * Records every explicit Vertex cache in `provider_cached_content` with
5	 * the required reuse policy fields at creation time, then drives the
6	 * lifecycle:
7	 *
8	 *   active  →  deleted (clean shutdown after final reuse)
9	 *            →  expired (TTL exceeded before final reuse)
10	 *            →  failed (deletion attempted and failed)
11	 *            →  orphaned (lifecycle could not be tracked)
12	 *
13	 * Per docs/oracle/02-provider-native-ai-architecture.md
14	 * "Explicit Cache Lifecycle Rule":
15	 *
16	 *   "Because explicit caches bill while they exist, workers must attach
17	 *    every cache to a short-lived reuse policy BEFORE creating it."
18	 *
19	 * R7 ships the bookkeeping helpers. R7 itself does NOT yet create real
20	 * Vertex caches — that requires the @google/genai SDK wired in. The
21	 * helpers are designed so the worker can call them around any cache
22	 * creator (real or stub) and the lifecycle audit trail is identical.
23	 */
24	
25	import { and, eq, sql } from 'drizzle-orm';
26	import { providerCachedContent, type OracleDb } from '@oracle/db';
27	
28	export interface RecordCacheCreationInput {
29	  db: OracleDb;
30	  provider: 'anthropic' | 'vertex' | 'openai';
31	  cacheKind: 'explicit' | 'implicit';
32	  /** sha256 of the cached source content. */
33	  sourceHash: string;
34	  sourceTokenEstimate?: number;
35	  sourceDescription?: string;
36	  /** Provider-side resource handle (Vertex cachedContent resource name). */
37	  providerResourceName?: string;
38	  /** Required: how many times the worker plans to use this cache. */
39	  expectedReuseCount: number;
40	  /** Identifier of the latest planned reuse step (for cleanup gating). */
41	  latestPlannedReuseStep?: string;
42	  /** Hard expiration — caches must NOT outlive this. */
43	  hardExpirationAt: Date;
44	  /** Worker/job responsible for cleanup. */
45	  cleanupOwner?: string;
46	  createdByJobRunId?: string;
47	  providerMetadataJson?: unknown;
48	}
49	
50	export interface CacheLifecycleHandle {
51	  /** provider_cached_content.id. */
52	  id: string;
53	}
54	
55	/**
56	 * Insert a `provider_cached_content` row with `status='active'`. Returns
57	 * the handle the worker uses to update the row later (bump reuse count,
58	 * mark deleted, etc.).
59	 */
60	export async function recordCacheCreation(input: RecordCacheCreationInput): Promise<CacheLifecycleHandle> {
61	  const [row] = await input.db
62	    .insert(providerCachedContent)
63	    .values({
64	      provider: input.provider,
65	      cacheKind: input.cacheKind,
66	      providerResourceName: input.providerResourceName ?? null,
67	      sourceHash: input.sourceHash,
68	      sourceTokenEstimate: input.sourceTokenEstimate ?? null,
69	      sourceDescription: input.sourceDescription ?? null,
70	      providerMetadataJson: input.providerMetadataJson ?? null,
71	      expectedReuseCount: input.expectedReuseCount,
72	      latestPlannedReuseStep: input.latestPlannedReuseStep ?? null,
73	      hardExpirationAt: input.hardExpirationAt,
74	      cleanupOwner: input.cleanupOwner ?? null,
75	      status: 'active',
76	      createdByJobRunId: input.createdByJobRunId ?? null,
77	    })
78	    .returning({ id: providerCachedContent.id });
79	  if (!row) throw new Error('provider_cached_content insert returned no row');
80	  return { id: row.id };
81	}
82	
83	/** Increment actual_reuse_count after each successful use of the cache. */
84	export async function recordCacheReuse(db: OracleDb, handle: CacheLifecycleHandle): Promise<void> {
85	  await db
86	    .update(providerCachedContent)
87	    .set({
88	      actualReuseCount: sql`${providerCachedContent.actualReuseCount} + 1`,
89	      updatedAt: new Date(),
90	    })
91	    .where(eq(providerCachedContent.id, handle.id));
92	}
93	
94	export type CacheTerminalStatus = 'deleted' | 'expired' | 'failed' | 'orphaned';
95	
96	export interface RecordCacheTerminationInput {
97	  db: OracleDb;
98	  handle: CacheLifecycleHandle;
99	  status: CacheTerminalStatus;
100	  reason: string;
101	}
102	
103	/**
104	 * Mark a cache deleted / expired / failed / orphaned. The CHECK constraint
105	 * on provider_cached_content enforces that `deleted_at IS NOT NULL` whenever
106	 * status is non-active.
107	 */
108	export async function recordCacheTermination(input: RecordCacheTerminationInput): Promise<void> {
109	  await input.db
110	    .update(providerCachedContent)
111	    .set({
112	      status: input.status,
113	      deletedAt: new Date(),
114	      statusReason: input.reason,
115	      updatedAt: new Date(),
116	    })
117	    .where(
118	      and(
119	        eq(providerCachedContent.id, input.handle.id),
120	        // Defensive: don't double-write a termination.
121	        eq(providerCachedContent.status, 'active'),
122	      ),
123	    );
124	}
