1	/**
2	 * R7 — Vertex explicit-cache profitability heuristic.
3	 *
4	 * Pure function. Encodes the rule from
5	 * docs/oracle/02-provider-native-ai-architecture.md "Explicit Cache Heuristic":
6	 *
7	 *   useExplicitGeminiCache =
8	 *     (sourceTokenEstimate >= 25_000 && expectedReuseCount >= 3)
9	 *     OR (sourceTokenEstimate >= 100_000 && expectedReuseCount >= 2)
10	 *
11	 * Vertex explicit caches bill while they exist. Creating one for a
12	 * one-off chunk or for a small reuse window is a net cost loss — the
13	 * storage fee outpaces the saved input-token spend. The heuristic
14	 * captures the break-even points conservatively. Workers call this
15	 * BEFORE creating the cache; if false, they fall back to implicit
16	 * caching (which is free and provider-managed).
17	 *
18	 * Returns a structured decision so the cache-lifecycle bookkeeping
19	 * (`provider_cached_content` row) can record the reasoning at creation
20	 * time.
21	 */
22	
23	export interface CacheProfitabilityInput {
24	  /** Estimated token count of the source content the cache would hold. */
25	  sourceTokenEstimate: number;
26	  /** How many times the worker plans to call against this cache. */
27	  expectedReuseCount: number;
28	}
29	
30	export type CacheProfitabilityDecision =
31	  | {
32	      kind: 'create_explicit_cache';
33	      rule: 'medium_source_high_reuse' | 'large_source_modest_reuse';
34	      detail: string;
35	    }
36	  | {
37	      kind: 'skip_explicit_cache';
38	      reason:
39	        | 'source_too_small'
40	        | 'reuse_too_low'
41	        | 'reuse_too_low_for_medium'
42	        | 'reuse_too_low_for_large';
43	      detail: string;
44	    };
45	
46	export const EXPLICIT_CACHE_MEDIUM_SOURCE_TOKEN_THRESHOLD = 25_000;
47	export const EXPLICIT_CACHE_MEDIUM_SOURCE_REUSE_THRESHOLD = 3;
48	export const EXPLICIT_CACHE_LARGE_SOURCE_TOKEN_THRESHOLD = 100_000;
49	export const EXPLICIT_CACHE_LARGE_SOURCE_REUSE_THRESHOLD = 2;
50	
51	/**
52	 * Cheap, deterministic token estimate for cache-profitability decisions.
53	 *
54	 * Uses the well-known 4-chars-per-token approximation. Provider-native
55	 * adapters will return real token counts after the call; the heuristic
56	 * here just needs a stable estimate to gate the create-or-skip decision
57	 * BEFORE the call.
58	 */
59	export function estimateTokensForCache(content: string): number {
60	  return Math.ceil(content.length / 4);
61	}
62	
63	export function decideCacheProfitability(input: CacheProfitabilityInput): CacheProfitabilityDecision {
64	  const { sourceTokenEstimate, expectedReuseCount } = input;
65	
66	  if (
67	    sourceTokenEstimate >= EXPLICIT_CACHE_LARGE_SOURCE_TOKEN_THRESHOLD &&
68	    expectedReuseCount >= EXPLICIT_CACHE_LARGE_SOURCE_REUSE_THRESHOLD
69	  ) {
70	    return {
71	      kind: 'create_explicit_cache',
72	      rule: 'large_source_modest_reuse',
73	      detail: `Source is large (${sourceTokenEstimate} ≥ ${EXPLICIT_CACHE_LARGE_SOURCE_TOKEN_THRESHOLD} tokens) and will be reused ${expectedReuseCount} ≥ ${EXPLICIT_CACHE_LARGE_SOURCE_REUSE_THRESHOLD} times.`,
74	    };
75	  }
76	
77	  if (
78	    sourceTokenEstimate >= EXPLICIT_CACHE_MEDIUM_SOURCE_TOKEN_THRESHOLD &&
79	    expectedReuseCount >= EXPLICIT_CACHE_MEDIUM_SOURCE_REUSE_THRESHOLD
80	  ) {
81	    return {
82	      kind: 'create_explicit_cache',
83	      rule: 'medium_source_high_reuse',
84	      detail: `Source is medium (${sourceTokenEstimate} ≥ ${EXPLICIT_CACHE_MEDIUM_SOURCE_TOKEN_THRESHOLD} tokens) and will be reused ${expectedReuseCount} ≥ ${EXPLICIT_CACHE_MEDIUM_SOURCE_REUSE_THRESHOLD} times.`,
85	    };
86	  }
87	
88	  if (sourceTokenEstimate < EXPLICIT_CACHE_MEDIUM_SOURCE_TOKEN_THRESHOLD) {
89	    return {
90	      kind: 'skip_explicit_cache',
91	      reason: 'source_too_small',
92	      detail: `Source is below the ${EXPLICIT_CACHE_MEDIUM_SOURCE_TOKEN_THRESHOLD}-token threshold (${sourceTokenEstimate}); explicit cache storage fees would outpace savings. Use implicit caching.`,
93	    };
94	  }
95	
96	  if (sourceTokenEstimate < EXPLICIT_CACHE_LARGE_SOURCE_TOKEN_THRESHOLD) {
97	    return {
98	      kind: 'skip_explicit_cache',
99	      reason: 'reuse_too_low_for_medium',
100	      detail: `Source is medium-sized but reuse count (${expectedReuseCount}) is below the ${EXPLICIT_CACHE_MEDIUM_SOURCE_REUSE_THRESHOLD}-pass threshold; use implicit caching.`,
101	    };
102	  }
103	
104	  return {
105	    kind: 'skip_explicit_cache',
106	    reason: 'reuse_too_low_for_large',
107	    detail: `Source is large but reuse count (${expectedReuseCount}) is below the ${EXPLICIT_CACHE_LARGE_SOURCE_REUSE_THRESHOLD}-pass threshold; use implicit caching.`,
108	  };
109	}
